class Solution:
    def solve(self, n: int) -> str:
        res = "1"
        for _ in range(n - 1):
            next_res = ""
            i = 0
            while i < len(res):
                count = 1
                while i + 1 < len(res) and res[i] == res[i + 1]:
                    count += 1
                    i += 1
                next_res += str(count) + res[i]
                i += 1
            res = next_res
        return res

